#!/usr/bin/env python3
"""Expression evaluator for ETL pipeline."""

import re

TWO_CHAR_OPS = {'==', '!=', '<=', '>=', '||', '&&'}


def tokenize(expr):
    """Tokenize expression string."""
    pos = 0
    length = len(expr)
    while pos < length:
        ch = expr[pos]
        if ch in ' \t\n\r':
            pos += 1
            continue
        if ch == '.' and pos + 1 < length and expr[pos + 1].isalpha():
            yield ('OPERATOR', '.')
            pos += 1
            continue
        if pos + 1 < length:
            two_char = expr[pos:pos + 2]
            if two_char in TWO_CHAR_OPS:
                yield ('OPERATOR', two_char)
                pos += 2
                continue
        if ch == '(':
            yield ('LPAREN', '(')
            pos += 1
            continue
        if ch == ')':
            yield ('RPAREN', ')')
            pos += 1
            continue
        if ch == '!':
            yield ('OPERATOR', '!')
            pos += 1
            continue
        if ch in '*/+-<>|&':
            yield ('OPERATOR', ch)
            pos += 1
            continue
        if ch == '"':
            pos += 1
            result = []
            while pos < length and expr[pos] != '"':
                result.append(expr[pos])
                pos += 1
            if pos >= length:
                raise ValueError("Unterminated string literal")
            pos += 1
            yield ('LITERAL', ''.join(result))
            continue
        if ch.isdigit() or (ch == '-' and pos + 1 < length and expr[pos + 1].isdigit()):
            start = pos
            if ch == '-':
                pos += 1
            while pos < length and (expr[pos].isdigit() or expr[pos] == '.'):
                pos += 1
            num_str = expr[start:pos]
            yield ('LITERAL', float(num_str) if '.' in num_str else int(num_str))
            continue
        for keyword in ['true', 'false', 'null']:
            if expr.startswith(keyword, pos):
                pos += len(keyword)
                if keyword == 'true':
                    yield ('LITERAL', True)
                elif keyword == 'false':
                    yield ('LITERAL', False)
                else:
                    yield ('LITERAL', None)
                break
        else:
            start = pos
            while pos < length and (expr[pos].isalnum() or expr[pos] == '_'):
                pos += 1
            ident = expr[start:pos]
            if ident:
                yield ('IDENTIFIER', ident)
                continue
            raise ValueError(f"Unexpected character: {ch}")


def parse_expression(tokens):
    """Parse tokens into AST."""
    tokens_iter = iter(tokens)
    current = None

    def advance():
        nonlocal current
        try:
            return next(tokens_iter)
        except StopIteration:
            return ('EOF', None)

    def peek():
        return current

    def expect(expected_type, error_msg):
        if peek()[0] != expected_type:
            raise ValueError(error_msg)
        t = peek()
        advance()
        return t

    def parse_primary():
        t = peek()
        if t[0] == 'LPAREN':
            advance()
            node = parse_or()
            expect('RPAREN', "Expected ')'")
            return node
        if t[0] == 'IDENTIFIER':
            advance()
            base = t[1]
            parts = [base]
            while peek()[0] == 'OPERATOR' and peek()[1] == '.':
                advance()
                expect('IDENTIFIER', "Expected identifier after '.'"))
                parts.append(t[1])
            return ('ident', parts[0]) if len(parts) == 1 else ('member_access', tuple(parts))
        if t[0] == 'LITERAL':
            advance()
            return ('literal', t[1])
        raise ValueError(f"Unexpected token: {t}")

    def parse_unary():
        if peek()[0] == 'OPERATOR' and peek()[1] == '!':
            advance()
            return ('!', parse_unary())
        if peek()[0] == 'OPERATOR' and peek()[1] == '-':
            advance()
            return ('-', parse_unary())
        return parse_primary()

    def parse_multiplicative():
        node = parse_unary()
        while peek()[0] == 'OPERATOR' and peek()[1] in ('*', '/'):
            op = peek()[1]
            advance()
            node = (op, node, parse_unary())
        return node

    def parse_additive():
        node = parse_multiplicative()
        while peek()[0] == 'OPERATOR' and peek()[1] in ('+', '-'):
            op = peek()[1]
            advance()
            node = (op, node, parse_multiplicative())
        return node

    def parse_comparison():
        node = parse_additive()
        while peek()[0] == 'OPERATOR' and peek()[1] in ('<', '<=', '>', '>='):
            op = peek()[1]
            advance()
            node = (op, node, parse_additive())
        return node

    def parse_equality():
        node = parse_comparison()
        while peek()[0] == 'OPERATOR' and peek()[1] in ('==', '!='):
            op = peek()[1]
            advance()
            node = (op, node, parse_comparison())
        return node

    def parse_and():
        node = parse_equality()
        while peek()[0] == 'OPERATOR' and peek()[1] == '&&':
            advance()
            node = ('and', node, parse_equality())
        return node

    def parse_or():
        node = parse_and()
        while peek()[0] == 'OPERATOR' and peek()[1] == '||':
            advance()
            node = ('or', node, parse_and())
        return node

    current = advance()
    return parse_or()


def evaluate_ast(ast, context, params=None):
