            advance()
            return ('-', parse_unary())
        return parse_primary()

    def parse_multiplicative():
        node = parse_unary()
        while peek()[0] == 'OPERATOR' and peek()[1] in ('*', '/'):
            op = peek()[1]
            advance()
            node = (op, node, parse_unary())
        return node

    def parse_additive():
        node = parse_multiplicative()
        while peek()[0] == 'OPERATOR' and peek()[1] in ('+', '-'):
            op = peek()[1]
            advance()
            node = (op, node, parse_multiplicative())
        return node

    def parse_comparison():
        node = parse_additive()
        while peek()[0] == 'OPERATOR' and peek()[1] in ('<', '<=', '>', '>='):
            op = peek()[1]
            advance()
            node = (op, node, parse_additive())
        return node

    def parse_equality():
        node = parse_comparison()
        while peek()[0] == 'OPERATOR' and peek()[1] in ('==', '!='):
            op = peek()[1]
            advance()
            node = (op, node, parse_comparison())
        return node

    def parse_and():
        node = parse_equality()
        while peek()[0] == 'OPERATOR' and peek()[1] == '&&':
            advance()
            node = ('and', node, parse_equality())
        return node

    def parse_or():
        node = parse_and()
        while peek()[0] == 'OPERATOR' and peek()[1] == '||':
            advance()
            node = ('or', node, parse_and())
        return node

    current = advance()
    return parse_or()


def evaluate_ast(ast, context, params=None):
    """Evaluate AST with context and params."""
    if params is None:
        params = {}

    node_type = ast[0]

